// Rate limit: don't fire more than once every 2 hours
const lastSpoke = flow.get('agent_last_spoke') || 0;
if (Date.now() - lastSpoke < 2 * 60 * 60 * 1000) {
  node.warn('Agent: rate limited');
  return null;
}

const now = new Date();
const time = now.toLocaleString('en-US', { weekday:'long', hour:'numeric', minute:'2-digit', hour12:true });

// Calendar
let calendar = 'No upcoming events';
try {
  const calEvents = flow.get('caroline_calendar') || global.get('caroline_calendar') || [];
  const soon = calEvents.filter(e => {
    const start = new Date(e.start || e.time || '');
    const diff = (start - now) / 60000;
    return diff >= -30 && diff <= 120;
  });
  if (soon.length) calendar = soon.slice(0,3).map(e => (e.summary || e.title || '?') + ' at ' + (e.start || e.time || '?')).join('; ');
} catch(e) {}

// Todos
let todos = 'No open tasks';
try {
  const todoList = flow.get('caroline_todos') || global.get('caroline_todos') || [];
  const open = todoList.filter(t => !t.done && !t.completed);
  if (open.length) todos = open.slice(0,5).map(t => t.name || t.task || t.text || '?').join(', ');
} catch(e) {}

// Weather
let weather = 'Weather unavailable';
try {
  const wx = flow.get('caroline_weather') || global.get('caroline_weather') || {};
  if (wx.temp) weather = wx.temp + '°F, ' + (wx.desc || wx.description || '').trim();
} catch(e) {}

// Recent chat (last 6 messages)
let recent_chat = 'No recent conversation';
try {
  const fs = global.get('fs');
  const raw = fs.readFileSync('/home/davee/caroline/caroline_history.json', 'utf8');
  const hist = JSON.parse(raw || '[]');
  const recent = hist.slice(-6);
  if (recent.length) {
    recent_chat = recent.map(m => (m.role === 'user' ? 'User' : 'Caroline') + ': ' + (m.content || m.text || '').slice(0, 80)).join('\n');
  }
} catch(e) {}

msg = { agentContext: { time, calendar, todos, weather, recent_chat } };
return msg;

const ctx = msg.agentContext;

const systemPrompt = `You are Caroline's autonomous context engine. You decide whether Caroline should proactively say something to the user right now.

Rules:
- Only speak if something is genuinely time-sensitive or useful
- Prefer brevity — one sentence max
- If nothing warrants attention, respond with exactly: SILENT
- No formatting, no markdown, no quotes`;

const userPrompt = `Current time: ${ctx.time}
Upcoming events: ${ctx.calendar}
Open tasks: ${ctx.todos}
Weather: ${ctx.weather}
Last conversation:
${ctx.recent_chat}

Should Caroline say something right now?`;

const provider = flow.get('aiProvider') || flow.get('ai_provider') || 'openrouter';
const model = provider === 'ollama'
  ? (flow.get('ollamaModel') || flow.get('ollama_model') || 'llama3.2')
  : (flow.get('aiModel') || flow.get('openrouter_model') || flow.get('ai_model') || 'anthropic/claude-haiku-4.5');

if (provider === 'ollama') {
  msg.url = (flow.get('ollamaUrl') || flow.get('ollama_url') || 'http://localhost:11434').replace(/\/+$/, '') + '/v1/chat/completions';
  msg.headers = { 'Content-Type': 'application/json' };
} else {
  msg.url = 'https://openrouter.ai/api/v1/chat/completions';
  const key = flow.get('openrouterKey') || '';
  msg.headers = { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + key };
}

msg.payload = {
  model,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: userPrompt }
  ],
  max_tokens: 80,
  temperature: 0.7
};

return msg;

try {
  const body = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
  const text = (body.choices?.[0]?.message?.content || body.message?.content || '').trim();

  if (!text || text.toUpperCase() === 'SILENT' || text.toUpperCase().startsWith('SILENT')) {
    node.warn('Agent: SILENT');
    return null;
  }

  flow.set('agent_last_spoke', Date.now());

  msg = { payload: JSON.stringify({ type: 'agent_message', text: text, source: 'proactive' }) };
  return msg;
} catch(e) {
  node.error('Agent parse error: ' + e.message);
  return null;
}
